commands_run:
/bin/zsh -lc "node <<'NODE'
const assert = require('assert');
const { diffServices } = require('./src/deploy/reconciler');

const a = { name: 'api', image: 'api:v1', replicas: 2 };
const w = { name: 'web', image: 'web:v1', replicas: 1 };
assert.deepStrictEqual(diffServices([a, w], [w, a]), []);
assert.deepStrictEqual(diffServices([{ ...a, image: 'api:v2' }], [a]), [
  { type: 'update', name: 'api', before: a, after: { ...a, image: 'api:v2' } },
]);
assert.deepStrictEqual(diffServices([a, w], [a]), [{ type: 'create', name: 'web' }]);
assert.deepStrictEqual(diffServices([a], [a, w]), [{ type: 'delete', name: 'web' }]);
console.log('manual reconciler assertions passed');
NODE"
